  1	import { ChartDonut, ChartLabel, ChartLegend, ChartThemeColor } from '@patternfly/react-charts/victory';
  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { GenericMetric, MetricStats, NamedMetric } from '../../api/loki';
  5	import { MetricFunction, MetricType } from '../../model/flow-query';
  6	import { getStat } from '../../model/metrics';
  7	import { localStorageOverviewDonutDimensionKey, useLocalStorage } from '../../utils/local-storage-hook';
  8	import { getFormattedValue, isUnknownPeer } from '../../utils/metrics';
  9	import { defaultDimensions, Dimensions, observeDimensions } from '../../utils/metrics-helper';
 10	import './metrics-content.css';
 11	
 12	export interface MetricsDonutProps {
 13	  id: string;
 14	  subTitle?: string;
 15	  limit: number;
 16	  metricType: MetricType;
 17	  metricFunction: MetricFunction;
 18	  topKMetrics: (GenericMetric | NamedMetric)[];
 19	  totalMetric: GenericMetric | NamedMetric;
 20	  showOthers: boolean;
 21	  othersName?: string;
 22	  showLast?: boolean;
 23	  showInternal?: boolean;
 24	  showOutOfScope?: boolean;
 25	  smallerTexts?: boolean;
 26	  showLegend?: boolean;
 27	  animate?: boolean;
 28	}
 29	
 30	export const MetricsDonut: React.FC<MetricsDonutProps> = ({
 31	  id,
 32	  subTitle,
 33	  metricFunction,
 34	  limit,
 35	  metricType,
 36	  topKMetrics,
 37	  totalMetric,
 38	  showOthers,
 39	  othersName,
 40	  showLast,
 41	  showInternal,
 42	  showOutOfScope,
 43	  smallerTexts,
 44	  showLegend,
 45	  animate
 46	}) => {
 47	  const { t } = useTranslation('plugin__netobserv-plugin');
 48	
 49	  const getStats = React.useCallback(
 50	    (stats: MetricStats) => {
 51	      return getStat(stats, showLast ? 'last' : metricFunction);
 52	    },
 53	    [metricFunction, showLast]
 54	  );
 55	
 56	  let total = getStats(totalMetric.stats);
 57	  let filtered = topKMetrics;
 58	  if (showOutOfScope === false) {
 59	    filtered = (filtered as NamedMetric[]).filter(m => {
 60	      if (isUnknownPeer(m.source) && isUnknownPeer(m.destination)) {
 61	        // This is full out-of-scope traffic. If it's hidden, remove it also from total
 62	        total -= getStats(m.stats);
 63	        return false;
 64	      }
 65	      return true;
 66	    });
 67	  }
 68	  if (showInternal === false) {
 69	    filtered = (filtered as NamedMetric[]).filter(m => {
 70	      if (m.isInternal) {
 71	        // This is internal traffic. If it's hidden, remove it also from total
 72	        total -= getStats(m.stats);
 73	        return false;
 74	      }
 75	      return true;
 76	    });
 77	  }
 78	  if (showOthers === false && othersName) {
 79	    // remove others from generic metrics (DNS rcode NoError)
 80	    filtered = (filtered as GenericMetric[]).filter(m => !othersName || m.name !== othersName);
 81	  }
 82	
 83	  let sliced = filtered
 84	    .map(m => ({
 85	      name: (m as NamedMetric).fullName || (m as GenericMetric).name,
 86	      shortName: (m as NamedMetric).shortName || (m as GenericMetric).name,
 87	      fullName: (m as NamedMetric).fullName || (m as GenericMetric).name,
 88	      value: getStats(m.stats)
 89	    }))
 90	    .sort((a, b) => b.value - a.value)
 91	    .slice(0, limit);
 92	
 93	  const others = Math.max(0, total - sliced.reduce((prev, cur) => prev + cur.value, 0));
 94	  if (showOthers) {
 95	    if (others > 0 && !othersName) {
 96	      sliced = [
 97	        ...sliced,
 98	        {
 99	          name: t('Others'),
100	          fullName: t('Others'),
101	          shortName: t('Others'),
102	          value: others
103	        }
104	      ];
105	    }
106	  } else {
107	    total -= others;
108	    sliced = sliced.filter(m => m.name !== (othersName || t('Others')));
109	  }
110	
111	  const legendData = sliced.map((m, idx) => ({
112	    childName: `${'area-'}${idx}`,
113	    name: m.name
114	  }));
115	
116	  const legentComponent = (
117	    <ChartLegend
118	      labelComponent={<ChartLabel className={smallerTexts ? 'small-chart-label' : ''} />}
119	      data={legendData}
120	    />
121	  );
122	
123	  const containerRef = React.useRef<HTMLDivElement>(null);
124	  const [dimensions, setDimensions] = useLocalStorage<Dimensions>(
125	    `${localStorageOverviewDonutDimensionKey}${showLegend ? '-legend' : ''}`,
126	    defaultDimensions
127	  );
128	  React.useEffect(() => {
129	    return observeDimensions(containerRef, dimensions, setDimensions);
130	  }, [containerRef, dimensions, setDimensions]);
131	
132	  return (
133	    <div id={id} className="metrics-content-div" ref={containerRef} data-test-metrics={topKMetrics.length}>
134	      <ChartDonut
135	        themeColor={ChartThemeColor.multiUnordered}
136	        constrainToVisibleArea
137	        legendData={showLegend ? legendData : undefined}
138	        legendOrientation="vertical"
139	        legendPosition="right"
140	        legendAllowWrap={true}
141	        legendComponent={showLegend ? legentComponent : undefined}
142	        radius={showLegend ? dimensions.height / 3 : undefined}
143	        innerRadius={showLegend ? dimensions.height / 4 : undefined}
144	        width={dimensions.width}
145	        height={dimensions.height}
146	        data={sliced.map(m => ({
147	          x: showLegend ? `${m.name}: ${getFormattedValue(m.value, metricType, metricFunction, t)}` : ' ',
148	          y: m.value
149	        }))}
150	        allowTooltip={showLegend}
151	        animate={animate}
152	        padding={
153	          showLegend
154	            ? {
155	                bottom: 20,
156	                left: 20,
157	                right: 400,
158	                top: 20
159	              }
160	            : {
161	                bottom: 0,
162	                left: 0,
163	                right: 0,
164	                top: 0
165	              }
166	        }
167	        title={`${getFormattedValue(total, metricType, metricFunction, t)}`}
168	        subTitle={subTitle ? subTitle : t('Total')}
169	      />
170	    </div>
171	  );
172	};

